javascript:(async()=>{try{const metaUrl=performance.getEntriesByType('resource').map(r=>r.name).find(x=>x.includes('/metadata/relations/folder/'));if(!metaUrl){alert('Metadata URL not found. Refresh the Power BI workspace page and try again.');return;}const res=await fetch(metaUrl,{method:'GET',credentials:'include',headers:{'Accept':'application/json, text/plain, */*','X-PowerBI-HostEnv':'Power BI Web App','X-Consuming-Feature':'ListView'}});if(!res.ok){const txt=await res.text();alert('Request failed: '+res.status+'\n'+txt.substring(0,500));return;}const json=await res.json();const artifacts=(json.artifacts||[]).map(a=>({id:a.id,objectId:a.objectId,displayName:a.displayName,typeName:a.typeName,subType:a.subType,isHidden:a.isHidden}));console.table(artifacts);const esc=v=>'"'+String(v??'').replace(/"/g,'""')+'"';const csv=['id,objectId,displayName,typeName,subType,isHidden',...artifacts.map(a=>[a.id,esc(a.objectId),esc(a.displayName),esc(a.typeName),esc(a.subType),a.isHidden].join(','))].join('\n');const blob=new Blob([csv],{type:'text/csv'});const link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download='powerbi-artifacts.csv';document.body.appendChild(link);link.click();setTimeout(()=>{URL.revokeObjectURL(link.href);link.remove();},2000);alert('Done. Extracted '+artifacts.length+' artifacts. CSV downloaded.');}catch(e){console.error(e);alert('Error: '+e);}})();
